mapper.select:
select spi.id as rowId,spi.name as name,csy.name as yearName, huser.name as headName,sdept.name as deptName, spi.issued_date as issuedDate,spi.end_date as endDate,spi.acceptance_date as acceptanceDate, spi.proj_status as projStatus,spi.special_funds as specialFunds,spi.project_account as projectAccount, spi.enterprise_funds as enterpriseFunds,spi.data_status as dataStatus,spi.sub_date as subDate,suser.name as subUserName from srm_contract_info spi left join ct_srm_proj_type cspt on cspt.code=spi.proj_type left join ct_srm_year csy on csy.code=spi.year left join ct_srm_dept sdept on sdept.id=spi.dept_id left join ct_srm_user huser on huser.id=spi.head left join ct_srm_discipline fdiscipline on fdiscipline.code=spi.discipline left join ct_srm_person_type ccspt on ccspt.code=spi.head_type_code left join ct_srm_proj_level cspl on cspl.code=spi.proj_level left join ct_srm_user suser on suser.id=spi.sub_user_id where (spi.sub_user_id=#{contractInfoDto.userId} or spi.id in (SELECT proj_id FROM srm_projects_info_member WHERE member = #{contractInfoDto.userId}) )
and spi.name LIKE CONCAT('%', #{contractInfoDto.name}, '%')
and spi.sub_date >= #{contractInfoDto.startDate}
and spi.sub_date <= #{contractInfoDto.endDate}
order by spi.id desc
